import Accordion from '@mui/material/Accordion';
import AccordionSummary from '@mui/material/AccordionSummary';
import AccordionDetails from '@mui/material/AccordionDetails';
import Typography from '@mui/material/Typography';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import { Blog } from "../blog/Blog";
import { Month } from "./Months";
import { Year } from "./Year"
import { useEffect, useState } from 'react';


const centerAlignStyle = {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
};
interface Blog {
    title: string;
    author: string;
    date: string;
    content: string;
}

interface Month {
    month: string;
    posts: Post[];
}

interface Year {
    year: string;
    months: Month[];
}

const sampleData: Year[] = [
    {
        year: "2023",
        months: [
            {
                month: "January",
                posts: [
                    {
                        title: "Learning React Today!",
                        author: "Cin Khai",
                        date: "10-12-2023",
                        content: "Today we will be learning React. I am going to be creating a blog post. There is a lot to learn and many hours I have. \
                        I must use my time wisely because it is so so easy to get distracted. Like it's actually insane how easily distracted you can get today. \
                        That's why we must stay focused!"
                    },
                    {
                        title: "Still learning React!",
                        author: "Cin Khai",
                        date: "10-13-2023",
                        content: "Today we are still learning react, a lot more JSON objects focused though to structure and organize my data"
                    }
                ]
            },
            {
                month: "February",
                posts: [
                    {
                        title: "Post 1",
                        author: "Author 1",
                        date: "02-12-2023",
                        content: "This is the content of Post 1 for February."
                    },
                ]
            }
        ]
    },
    {
        year: "2015",
        months: [
            {
                month: "August",
                posts: [
                    {
                        title: "Exploring the Mysteries of Deep Space",
                        author: "John Astronomer",
                        date: "2023-08-15",
                        content: "In a groundbreaking discovery, astronomers have uncovered new information about the origins of distant galaxies..."
                    }
                ]
            },
            {
                month: "September",
                posts: [
                    {
                        title: "The Art of Gourmet Cooking",
                        author: "Chef Emily Cuisine",
                        date: "2023-09-02",
                        content: "Indulge in the world of culinary delights as we dive into the secrets behind creating exquisite gourmet dishes..."
                    }
                ]
            }
        ]
    },
    {
        year: "2022",
        months: [
            {
                month: "July",
                posts: [
                    {
                        title: "Green Energy Revolution: Solar Power's Rise",
                        author: "Sarah Environmentalist",
                        date: "2023-07-22",
                        content: "As the world shifts towards sustainability, solar power is emerging as a key player in the global quest for clean energy..."
                    }

                ]
            }
        ]
    }
]

export const Timeline = () => {
    const [expandYear, setExpandYear] = useState<string | null>(null);
    const [expandMonth, setExpandMonth] = useState<{ year: string; month: string } | null>(null);
    const [blogData, setBlogData] = useState({});

    const handleExpandYear = (panel: string) => (event: React.ChangeEvent<{}>, isExpanded: boolean) => {
        setExpandYear(isExpanded ? panel : null);
    }

    const handleExpandMonth = (year: string, month: string) => (event: React.ChangeEvent<{}>, isExpanded: boolean) => {
        setExpandMonth(isExpanded ? { year, month } : null);
    }

    const[blogs, setBlogs] = useState([]);

    useEffect(() => {
        fetch('http://localhost:4000/get-blogs').then(blogData => {
            blogData.json().then(jsonBlog => {
                console.log(jsonBlog);
            });
        });
    })

    const formatBlogDisplay = (blogData: Blog) => {


    }


    return (
        <div className="wrapper">
            {sampleData.map((outerData, outerIndex) => (
                <Accordion className="blog-content"
                    key={outerIndex}
                    expanded={expandYear === outerData.year}
                    onChange={handleExpandYear(outerData.year)}
                >
                    <AccordionSummary  expandIcon={<ExpandMoreIcon />}>
                        <Typography>{outerData.year}</Typography>
                    </AccordionSummary>

                    <AccordionDetails >
                        {outerData.months.map((innerData, innerIndex) => (
                            <Accordion
                                key={innerIndex}
                                expanded={expandMonth?.year === outerData.year && expandMonth?.month === innerData.month}
                                onChange={handleExpandMonth(outerData.year, innerData.month)}
                            >
                                <AccordionSummary expandIcon={<ExpandMoreIcon />} >
                                    <Typography >{innerData.month}</Typography>
                                </AccordionSummary>
                                <AccordionDetails>
                                    {innerData.posts.map((postData, postIndex) => (
                                        <div key={postIndex}>
                                            <Typography><strong>{postData.title}</strong> </Typography>
                                            <Typography><strong>Author:</strong> {postData.author}</Typography>
                                            <Typography><strong>Date:</strong> {postData.date}</Typography>
                                            <Typography><strong></strong> {postData.content}</Typography>
                                            <p></p>
                                        </div>
                                    ))}
                                </AccordionDetails>
                            </Accordion>
                        ))}
                    </AccordionDetails>
                </Accordion>
            ))};
        </div>
    )
}















